import * as React from "react";

function YesFifthPageYes() {



    document.addEventListener('DOMContentLoaded', function () {
        const checkboxes = document.querySelectorAll('.checkbox');

        checkboxes.forEach(checkbox => {
            checkbox.addEventListener('change', function () {
                const label = this.nextElementSibling.querySelector('.checkbox-label');
                if (this.checked) {
                    label.style.color = 'green'; // Example: Change label color when checked
                    console.log(`${this.id} is checked!`);
                } else {
                    label.style.color = ''; // Reset label color when unchecked
                    console.log(`${this.id} is unchecked!`);
                }
            });
        });
    });



    return (
        <>
            <div className="div-71">
                <div className="div-72">
                    Private Pension
                    <br />
                    Withdrawal
                </div>
                <div className="div-73">
                    Have you withdrawn money from any of your private pensions?
                </div>
                <div className="div-74">
                    <div className="div-75">YES</div>
                    <div className="div-76">NO</div>
                </div>
                <div className="div-77">
                    Please select the pensions you have withdrawn money from{" "}
                </div>
                <div className="div-78">
                    <div className="div-79">
                        <div className="div-710">
                            <div className="div-711" />
                            <div className="div-712" />
                        </div>
                        <div className="div-713">
                            <div class="white-box">
                                <input type="checkbox" class="checkbox" id="checkbox1"/>
                                    <label for="checkbox1" class="checkbox-label"></label>
                                    <div className="div-714">AVIVA</div>
                                    <div className="div-715">Policy No. A12456W34</div>
                            </div>

                            <div class="white-box">
                                <input type="checkbox" class="checkbox" id="checkbox2"/>
                                    <label for="checkbox2" class="checkbox-label">Checkbox 2</label>
                            </div>

                            <div class="white-box">
                                <input type="checkbox" class="checkbox" id="checkbox3"/>
                                    <label for="checkbox3" class="checkbox-label">Checkbox 3</label>
                            </div>
                            {/* <div className="div-714">AVIVA</div>
                            <div className="div-715">Policy No. A12456W34</div> */}
                            <div className="div-716">AEGON</div>
                            <div className="div-717">Policy No. B23311B21</div>
                        </div>
                    </div>
                    <div className="div-718">
                        <div className="div-719" />
                        <div className="div-720">
                            <div className="div-721">Prudential</div>
                            <div className="div-722">Policy No. Z2221GH2</div>
                        </div>
                    </div>
                </div>
            </div>
        </>
    );
}

export default YesFifthPageYes;
